cd /c/Users/EDY/AppData/Local/Temp/claude/D--nexgaios-amazon/75bfbc79-d177-409b-9ee2-61bd87ae42dd/scratchpad && cat > q3_calc2.py << 'EOF'
import csv
from collections import defaultdict
lp="C:/Users/EDY/AppData/Local/Temp/claude/D--nexgaios-amazon/75bfbc79-d177-409b-9ee2-61bd87ae42dd/scratchpad/lingxing_snapshot/asin_monthly.csv"
rows=list(csv.DictReader(open(lp,encoding="utf-8-sig")))

# clean margin: avg of 2026-04 & 2026-05 (DD+7 settled, post return-storm), net-weighted
clean_m={"2026-04","2026-05"}
agg=defaultdict(lambda:{"net":0.0,"gp":0.0})
mo={}
for r in rows:
    if r["month"] in clean_m and float(r["volume"])>0:
        a=r["asin"];mo[a]=r["model"]
        net=float(r["net_amount"]);gm=float(r["gross_margin"])
        agg[a]["net"]+=net;agg[a]["gp"]+=net*gm
print("=== CLEAN MARGIN (2026-04+05 net-weighted), lingxing ===")
for a,v in sorted(agg.items(),key=lambda kv:-kv[1]["gp"]/kv[1]["net"]):
    print(f"{a} {mo[a]:10} margin {v['gp']/v['net']*100:>5.1f}%  gp${v['gp']:>10,.0f}")

# S3 ramp trajectory (brand-merged)
print("\n=== S3 (B0FNCQW2K3) ramp, lingxing brand-merged vol ===")
s3=defaultdict(float)
for r in rows:
    if r["asin"]=="B0FNCQW2K3": s3[r["month"]]+=float(r["volume"])
for m in sorted(s3): 
    if s3[m]>0: print(f"  {m}: {s3[m]:.0f} units")

# SQP imp_share (core) avg per asin -- who is the traffic/impression entry
sp="C:/Users/EDY/AppData/Local/Temp/claude/D--nexgaios-amazon/75bfbc79-d177-409b-9ee2-61bd87ae42dd/scratchpad/sqp_digests/sqp_asin_monthly.csv"
srows=[r for r in csv.DictReader(open(sp,encoding="utf-8-sig")) if r["uni"]=="core"]
imp=defaultdict(list);ords=defaultdict(list);smo={}
for r in srows:
    a=r["asin"];smo[a]=r["model"]
    imp[a].append(float(r["imp_share"]));ords[a].append(float(r["ord_share"]))
print("\n=== SQP core avg imp_share & ord_share (% of category), SQP ===")
for a in sorted(imp,key=lambda a:-sum(imp[a])/len(imp[a])):
    print(f"  {a} {smo[a]:10} imp_share {sum(imp[a])/len(imp[a]):>5.2f}%  ord_share {sum(ords[a])/len(ords[a]):>5.2f}%")

# S3 SQP ord_share trajectory
print("\n=== S3 SQP core ord_share ramp ===")
for r in srows:
    if r["asin"]=="B0FNCQW2K3": print(f"  {r['month']}: imp {r['imp_share']}%  ord {r['ord_share']}%")
EOF
